  esphome_lv_default_font = font_lbl->get_lv_font();
  LvglComponent::esphome_lvgl_init();
  lv_group_t_id = lv_group_create();
  lv_group_set_default(lv_group_t_id);
  lvgl_lvglcomponent_id = new lvgl::LvglComponent({round_display}, 0.0f, false, 2, true, false);
  lvgl_lvglcomponent_id->set_update_interval(1000);
  lvgl_lvglcomponent_id->set_component_source(LOG_STR("lvgl"));
  App.register_component_(lvgl_lvglcomponent_id);
  lvgl_lvtouchlistener_id = new lvgl::LVTouchListener(400, 100, lvgl_lvglcomponent_id);
  lv_indev_drv_register(lvgl_lvtouchlistener_id->get_drv());
  touch->register_listener(lvgl_lvtouchlistener_id);
  lvgl_lvencoderlistener_id = new lvgl::LVEncoderListener(::LV_INDEV_TYPE_ENCODER, 400, 100);
  lvgl_lvencoderlistener_id->set_parent(lvgl_lvglcomponent_id);
