  lambdaaction_id_42 = new StatelessLambdaAction<>([]() -> void {
      #line 153 "src/pages/timer.yaml"
      int   rem     = timer_remaining->value();
      int   total   = timer_total->value();
      bool  running = timer_running->value();
      bool  done    = timer_done->value();
      bool  blink   = timer_blink->value();
      int   unit    = timer_unit->value();
      bool  editing = !running && !done;
      
      float pct = editing ? 1.0f
                : (total > 0 ? (float)rem / (float)total : 0.0f);
      
       
      lv_color_t accent, dim;
      if (done) {
        accent = lv_color_hex(0xf87171);
        dim    = lv_color_hex(0x7f1d1d);
      } else if (editing || pct > 0.5f) {
        accent = lv_color_hex(0x4ade80);
        dim    = lv_color_hex(0x166534);
      } else if (pct > 0.2f) {
        accent = lv_color_hex(0xfb923c);
        dim    = lv_color_hex(0x9a3412);
      } else {
        accent = lv_color_hex(0xf87171);
        dim    = lv_color_hex(0x7f1d1d);
      }
      
       
      lv_arc_set_value(arc_timer, (int)(pct * 100.0f));
      lv_obj_set_style_arc_color(arc_timer, accent, LV_PART_INDICATOR);
      
       
      int disp_h, disp_m, disp_s;
      if (editing) {
        disp_h = timer_set_h->value();
        disp_m = timer_set_m->value();
        disp_s = timer_set_s->value();
      } else {
        disp_h = rem / 3600;
        disp_m = (rem % 3600) / 60;
        disp_s = rem % 60;
      }
      static char tbuf[9];
      snprintf(tbuf, sizeof(tbuf), "%02d:%02d:%02d", disp_h, disp_m, disp_s);
      lv_label_set_text(lbl_timer_time, tbuf);
      if (done && !blink) {
        lv_obj_set_style_text_color(lbl_timer_time, lv_color_hex(0x222222), 0);
      } else {
        lv_obj_set_style_text_color(lbl_timer_time,
          done ? accent : lv_color_hex(0xffffff), 0);
      }
      
       
      lv_obj_t* unit_btns[3] = {
        btn_timer_h, btn_timer_m, btn_timer_s
      };
      for (int i = 0; i < 3; i++) {
        bool active = editing && (unit == i);
        lv_obj_set_style_bg_color(unit_btns[i],
          active ? dim : lv_color_hex(0x1a1a1a), LV_PART_MAIN);
        lv_obj_set_style_border_color(unit_btns[i],
          active ? accent : lv_color_hex(0x2d2d2d), LV_PART_MAIN);
        lv_obj_t* child = lv_obj_get_child(unit_btns[i], 0);
        if (child)
          lv_obj_set_style_text_color(child,
            active ? accent : lv_color_hex(0x555555), 0);
      }
  });
